import{_ as e,c as a,o as l,ah as r}from"./chunks/framework.Cnj7lwEt.js";const g=JSON.parse('{"title":"Prompt-Engineering-Guide","description":"","frontmatter":{},"headers":[],"relativePath":"github汇总/AI工具/Prompt-Engineering-Guide-AI工具.md","filePath":"github汇总/AI工具/Prompt-Engineering-Guide-AI工具.md"}'),n={name:"github汇总/AI工具/Prompt-Engineering-Guide-AI工具.md"};function t(o,i,h,d,p,s){return l(),a("div",null,i[0]||(i[0]=[r('<h1 id="prompt-engineering-guide" tabindex="-1">Prompt-Engineering-Guide <a class="header-anchor" href="#prompt-engineering-guide" aria-label="Permalink to “Prompt-Engineering-Guide”">​</a></h1><h2 id="项目名称" tabindex="-1">项目名称 <a class="header-anchor" href="#项目名称" aria-label="Permalink to “项目名称”">​</a></h2><p>Prompt-Engineering-Guide</p><h2 id="作者或组织名" tabindex="-1">作者或组织名 <a class="header-anchor" href="#作者或组织名" aria-label="Permalink to “作者或组织名”">​</a></h2><p>dair-ai</p><h2 id="项目类别" tabindex="-1">项目类别 <a class="header-anchor" href="#项目类别" aria-label="Permalink to “项目类别”">​</a></h2><p>AI工具</p><h2 id="核心痛点" tabindex="-1">核心痛点 <a class="header-anchor" href="#核心痛点" aria-label="Permalink to “核心痛点”">​</a></h2><p>开发者想要系统学习提示词工程但找不到权威、全面的资料。</p><h2 id="主要功能" tabindex="-1">主要功能 <a class="header-anchor" href="#主要功能" aria-label="Permalink to “主要功能”">​</a></h2><p>全面的提示词工程指南，包含所有关于大语言模型提示词工程的最新论文、学习指南、讲座、参考资料和工具。涵盖提示词工程的基础知识（LLM设置、提示词基础、提示词元素、设计技巧）和高级技术（零样本提示、少样本提示、思维链推理、自一致性、知识生成提示、提示链、思维树、检索增强生成、自动推理与工具使用等）。提供针对不同模型（ChatGPT、Gemini、GPT-4、LLaMA、Mistral等）的专门指南。包含风险与误用分析、论文集、工具集、笔记本和数据集。</p><h2 id="项目亮点" tabindex="-1">项目亮点 <a class="header-anchor" href="#项目亮点" aria-label="Permalink to “项目亮点”">​</a></h2><ul><li>支持13种语言</li><li>帮助超过300万学习者</li><li>曾在Hacker News排名第一</li><li>提供1小时视频讲座</li><li>包含代码笔记本和数据集</li><li>被Wall Street Journal、Forbes等媒体报道</li></ul><h2 id="荣誉信息" tabindex="-1">荣誉信息 <a class="header-anchor" href="#荣誉信息" aria-label="Permalink to “荣誉信息”">​</a></h2><ul><li>300万+学习者</li><li>Hacker News排名第一</li><li>被Wall Street Journal、Forbes、Markettechpost等媒体报道</li></ul><h2 id="项目地址" tabindex="-1">项目地址 <a class="header-anchor" href="#项目地址" aria-label="Permalink to “项目地址”">​</a></h2><p><a href="https://github.com/dair-ai/Prompt-Engineering-Guide" target="_blank" rel="noreferrer">https://github.com/dair-ai/Prompt-Engineering-Guide</a> <a href="/网络环境.html">海外网络环境配置 →</a></p><h2 id="安装或部署教程" tabindex="-1">安装或部署教程 <a class="header-anchor" href="#安装或部署教程" aria-label="Permalink to “安装或部署教程”">​</a></h2><h3 id="教程适用对象与环境范围" tabindex="-1">教程适用对象与环境范围 <a class="header-anchor" href="#教程适用对象与环境范围" aria-label="Permalink to “教程适用对象与环境范围”">​</a></h3><p>本教程适用于想要本地运行Prompt-Engineering-Guide网站的用户。</p><h3 id="前置条件检查" tabindex="-1">前置条件检查 <a class="header-anchor" href="#前置条件检查" aria-label="Permalink to “前置条件检查”">​</a></h3><ol><li><p><strong>检查Node.js版本</strong></p><ul><li>执行命令：<code>node -v</code></li><li>通过标准：显示Node.js 18.0.0或更高版本</li></ul></li><li><p><strong>检查pnpm是否安装</strong></p><ul><li>执行命令：<code>pnpm -v</code></li><li>通过标准：显示pnpm版本号</li></ul></li></ol><h3 id="主路径-使用在线版本-推荐" tabindex="-1">主路径：使用在线版本（推荐） <a class="header-anchor" href="#主路径-使用在线版本-推荐" aria-label="Permalink to “主路径：使用在线版本（推荐）”">​</a></h3><p><strong>步骤1：访问在线指南</strong></p><ul><li>目标：直接使用在线版本学习</li><li>位置：浏览器</li><li>操作：访问 <a href="https://www.promptingguide.ai/" target="_blank" rel="noreferrer">https://www.promptingguide.ai/</a></li><li>成功标志：页面正常加载</li><li>失败处理：检查网络连接</li></ul><h3 id="备选路径-本地运行" tabindex="-1">备选路径：本地运行 <a class="header-anchor" href="#备选路径-本地运行" aria-label="Permalink to “备选路径：本地运行”">​</a></h3><p><strong>步骤1：克隆项目</strong></p><ul><li>目标：获取项目源码</li><li>位置：本地开发目录</li><li>命令：<code>git clone https://github.com/dair-ai/Prompt-Engineering-Guide.git</code></li><li>成功标志：项目目录创建成功</li><li>失败处理：检查网络连接</li></ul><p><strong>步骤2：安装依赖</strong></p><ul><li>目标：安装项目依赖</li><li>位置：项目目录</li><li>命令：<code>pnpm i next react react-dom nextra nextra-theme-docs</code></li><li>成功标志：依赖安装完成</li><li>失败处理：检查pnpm是否正确安装</li></ul><p><strong>步骤3：启动开发服务</strong></p><ul><li>目标：启动本地网站</li><li>位置：项目目录</li><li>命令：<code>pnpm dev</code></li><li>成功标志：服务启动，显示本地地址</li><li>失败处理：检查端口是否被占用</li></ul><p><strong>步骤4：访问本地网站</strong></p><ul><li>目标：在浏览器中查看</li><li>位置：浏览器</li><li>操作：访问 <a href="http://localhost:3000/" target="_blank" rel="noreferrer">http://localhost:3000/</a></li><li>成功标志：网站正常显示</li><li>失败处理：检查服务是否正常运行</li></ul><h3 id="安装成功验证" tabindex="-1">安装成功验证 <a class="header-anchor" href="#安装成功验证" aria-label="Permalink to “安装成功验证”">​</a></h3><ul><li>在线版本：页面正常加载，可以浏览各章节内容</li><li>本地版本：本地服务正常启动，可以访问localhost:3000</li></ul><h3 id="常见错误排查" tabindex="-1">常见错误排查 <a class="header-anchor" href="#常见错误排查" aria-label="Permalink to “常见错误排查”">​</a></h3><ol><li><p><strong>pnpm命令不存在</strong></p><ul><li>可能原因：pnpm未安装</li><li>解决步骤：运行 <code>npm install -g pnpm</code> 安装pnpm</li></ul></li><li><p><strong>依赖安装失败</strong></p><ul><li>可能原因：网络问题</li><li>解决步骤：切换npm源或使用代理</li></ul></li><li><p><strong>端口3000被占用</strong></p><ul><li>可能原因：其他服务占用端口</li><li>解决步骤：修改启动端口或关闭占用服务</li></ul></li></ol><h3 id="官方文档" tabindex="-1">官方文档 <a class="header-anchor" href="#官方文档" aria-label="Permalink to “官方文档”">​</a></h3><ul><li><a href="https://www.promptingguide.ai/" target="_blank" rel="noreferrer">Prompt Engineering Guide Website</a> <a href="/网络环境.html">海外网络环境配置 →</a></li></ul>',40)]))}const m=e(n,[["render",t]]);export{g as __pageData,m as default};
